	sv->cus       = 8.162856101990e-06;
	sv->crc       = 222.65625;
	sv->crs       = -48.0625;
	sv->cic       = 1.043081283569e-07;
	sv->cis       = 1.303851604462e-07;
	sv->tgd       = -1.117587089539e-08;

	/* QZSS PRN 193 */
	data->num_qzss = 1;
