	qzss->omega_dot = -6.0e-09;
	qzss->idot      = 1.0e-10;

	/* Almanac PRN 1 (angles in semi-circles) */
	data->num_alm = 1;
	struct gps_almanac *alm = &data->alm[0];
	alm->prn       = 1;
	alm->health    = 0;
	alm->ioda      = 2;
	alm->week      = 2409;
	alm->toa       = 405504;
	alm->e         = 5.48e-03;
	alm->delta_i   = -1.54e-03;
	alm->omega_dot = -2.48e-09;
	alm->sqrt_a    = 5153.65;
	alm->omega0    = -0.644;
	alm->omega     = -0.548;
