/*
 * Run C conversions via gps_assist_inject_*() public API.
 * The mock nrf_modem_gnss_agnss_write() captures each struct.
 */
static void run_c_conversions(const struct gps_assist_data *data)
{
	num_captures = 0;

	/* GPS ephemeris PRN 1 */
	gps_assist_inject_ephemeris(data, 1);

	/* GPS almanac PRN 1 (will use parsed almanac) */
	gps_assist_inject_almanac(data, 1);

	/* QZSS ephemeris PRN 193 */
	gps_assist_inject_qzss_ephemeris(data, 193);

	/* Klobuchar */
	gps_assist_inject_klobuchar(data);

	/* UTC */
	gps_assist_inject_utc(data);

	/* System time */
	gps_assist_inject_system_time(data);

	/* Location */
	gps_assist_inject_location(data);
}

int main(int argc, char *argv[])
{
	if (argc < 2) {
		fprintf(stderr, "Usage: %s <binary_file>\n", argv[0]);
		return 1;
	}

	printf("=== test_nrf_cloud_cross: PHP vs C cross-validation ===\n");

	/* Step 1: Run C conversions to produce reference structs */
	struct gps_assist_data data;

	setup_test_data(&data);
	run_c_conversions(&data);

	printf("  C conversions: %d captures\n", num_captures);
	ASSERT_TEST(num_captures == 7, "expected 7 captures");

	/* Step 2: Read PHP binary file */
	FILE *f = fopen(argv[1], "rb");
	if (!f) {
		fprintf(stderr, "Cannot open %s\n", argv[1]);
		return 1;
	}

	fseek(f, 0, SEEK_END);
	long file_size = ftell(f);
	fseek(f, 0, SEEK_SET);

	uint8_t *blob = malloc((size_t)file_size);
	if (!blob || fread(blob, 1, (size_t)file_size, f) != (size_t)file_size) {
		fprintf(stderr, "Failed to read %s\n", argv[1]);
		return 1;
	}
	fclose(f);

	printf("  PHP binary: %ld bytes\n", file_size);

	/* Step 3: Verify schema version */
	ASSERT_EQ_INT(blob[0], 1, "schema version");

	/* Step 4: Walk element groups and compare */
	int pos = 1;
	int groups_found = 0;

	while (pos < file_size) {
		int type_id = blob[pos];
		int count   = rd_u16(blob, pos + 1);
		int elem_sz = wire_element_size(type_id);
		pos += 3;

		if (elem_sz < 0) {
			fprintf(stderr, "  Unknown type %d at offset %d\n",
				type_id, pos - 3);
			break;
		}

		printf("  type=%d count=%d elem_size=%d\n",
			type_id, count, elem_sz);

		for (int i = 0; i < count; i++) {
			const uint8_t *elem = blob + pos;
			int ci;

			switch (type_id) {
			case CLOUD_TYPE_EPHEMERIS:
				/* Map to modem type 2, find by sv_id */
				ci = find_capture(
					NRF_MODEM_GNSS_AGNSS_GPS_EPHEMERIDES,
					elem[0]);
				if (ci >= 0)
					compare_ephemeris(elem, ci,
							  "GPS eph");
				else
					ASSERT_TEST(0, "GPS eph: no C capture");
				break;

			case CLOUD_TYPE_QZSS_EPH:
				/* QZSS uses same modem type 2 */
				ci = find_capture(
					NRF_MODEM_GNSS_AGNSS_GPS_EPHEMERIDES,
					elem[0]);
				if (ci >= 0)
					compare_ephemeris(elem, ci,
							  "QZSS eph");
				else
					ASSERT_TEST(0, "QZSS eph: no C capture");
				break;

			case CLOUD_TYPE_ALMANAC:
				ci = find_capture(
					NRF_MODEM_GNSS_AGNSS_GPS_ALMANAC,
					elem[0]);
				if (ci >= 0)
					compare_almanac(elem, ci,
							"GPS alm");
				else
					ASSERT_TEST(0, "GPS alm: no C capture");
				break;

			case CLOUD_TYPE_KLOBUCHAR:
				ci = find_capture(
					NRF_MODEM_GNSS_AGNSS_KLOBUCHAR_IONOSPHERIC_CORRECTION,
					-1);
				if (ci >= 0)
					compare_klobuchar(elem, ci);
				else
					ASSERT_TEST(0, "klob: no C capture");
				break;

			case CLOUD_TYPE_UTC:
				ci = find_capture(
					NRF_MODEM_GNSS_AGNSS_GPS_UTC_PARAMETERS,
					-1);
				if (ci >= 0)
					compare_utc(elem, ci);
				else
					ASSERT_TEST(0, "utc: no C capture");
				break;

			case CLOUD_TYPE_SYSTEM_CLOCK:
				ci = find_capture(
					NRF_MODEM_GNSS_AGNSS_GPS_SYSTEM_CLOCK_AND_TOWS,
					-1);
				if (ci >= 0)
					compare_system_time(elem, ci);
				else
					ASSERT_TEST(0, "stime: no C capture");
				break;

			case CLOUD_TYPE_LOCATION:
				ci = find_capture(
					NRF_MODEM_GNSS_AGNSS_LOCATION,
					-1);
				if (ci >= 0)
					compare_location(elem, ci);
				else
					ASSERT_TEST(0, "loc: no C capture");
				break;

			case CLOUD_TYPE_INTEGRITY:
				ASSERT_EQ_INT(rd_u32(elem, 0),
					      0xFFFFFFFF,
					      "integrity: all healthy");
				break;
			}

			pos += elem_sz;
		}

		groups_found++;
	}

	ASSERT_EQ_INT(pos, file_size, "fully consumed");
	ASSERT_TEST(groups_found >= 7, "at least 7 element groups");

	free(blob);

	printf("\ntest_nrf_cloud_cross: %d/%d passed\n",
		tests_passed, tests_run);
	return tests_passed < tests_run ? 1 : 0;
}
